/*    _   __   ___    _   ____    _    _        _____    ___     _____     | | / /  / _ \  | | |  _ \  | |  | |      |___  |  / _ \   |  ___|     | |/ /  | |_| | | | | |_| | |  \/  |         / /  | |_| |  | |__     |   /   |  _  | | | |  _ /  | |\/| |        / /   |  _  |  |  __|     | |\ \  | | | | | | | | \ \ | |  | |       / /__  | | | |  | |     |_| \_\ |_| |_| |_| |_| |_| |_|  |_|      |_____| |_| |_|  |_|      */#include<bits/stdc++.h>typedef long long ll;using namespace std;#ifndef ONLINE_JUDGE#include "debug.cpp"#else#define kar(...)#endif#define pb push_back#define F first#define S second#define all(x) x.begin(),x.end()#define rall(x) x.rbegin(),x.rend()#define int ll#define endl '\n' const int N = 1e5 + 30, mod = 1e9 + 7, INF = 1e18 + 10;  int add(int a, int b,int Mod = mod) { return ((a % Mod + b % Mod) % Mod + Mod) % Mod; }  int dp[N][105];int n, m, k;vector<int> v(N);vector<int> mp[N]; int work(int pos, int modulo) {    if (pos > n) return 0;    int& ret = dp[pos][modulo];    if (ret != -1) return ret;    ret = (modulo == k - 1);    if (modulo == 0) {        // manichi bch nekhou rouhi        ret = add(ret, work(pos + 1, modulo));    }    if (modulo == k - 1) {        ret = add(ret, work(pos + 1, 0));    }    auto nxt = upper_bound(all(mp[v[pos] % m]), pos);    if (nxt != mp[v[pos] % m].end()) {        if (modulo != k - 1) ret = add(ret, work(*nxt, (modulo + 1) % k));        //manichi bch nekhou rouhi        if (modulo) ret = add(ret, work(*nxt, modulo));    }    return ret;} void Solve() {     cin >> n >> m >> k;    for (int i = 1; i <= n; i++) {        cin >> v[i];        mp[v[i] % m].pb(i);    }    for (int i = 0; i <= n + 1; i++) {        for (int j = 0; j <= k + 1; j++) {            dp[i][j] = dp[i][j] = -1;        }    }     cout << work(1, 0) << endl;      for (int i = 1; i <= n; i++) mp[v[i] % m].clear();} int32_t main() {#ifndef ONLINE_JUDGE    freopen("input.txt", "r",stdin);    freopen("output.txt", "w",stdout);#endif    freopen("fortune.in", "r",stdin);    ios::sync_with_stdio(0), cin.tie(0);    int Test_case = 1;    cin >> Test_case;    while (Test_case--) Solve();}